/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements NotificationAdapter for the 'email' channel with:
 * - Template rendering per notification type
 * - Recipient validation and resolution
 * - Configurable email transport (defaults to in-memory for testing)
 *
 * Architecture constraint: all notification delivery goes through
 * adapters implementing NotificationAdapter, registered via
 * NotificationService.registerAdapter().
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  body: string;
  html: string;
  sentAt: Date;
  notificationId: string;
}

export interface EmailConfig {
  /** Sender address for outgoing emails. */
  fromAddress: string;
  /** Application name used in templates. */
  appName: string;
  /** Optional transport function for sending emails. Defaults to in-memory storage. */
  transport?: EmailTransport;
}

/**
 * Pluggable email transport. Return true for success, throw for failure.
 * In production, this would wrap an SMTP client, SES, SendGrid, etc.
 */
export type EmailTransport = (message: EmailMessage) => Promise<boolean>;

/** Template rendering context built from a NotificationPayload. */
interface TemplateContext {
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  appName: string;
  year: number;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const DEFAULT_CONFIG: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];
  private config: EmailConfig;

  constructor(config?: Partial<EmailConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Send an email notification.
   * Validates recipient, renders templates, and delivers via transport.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedRecipient = this.resolveRecipient(payload.recipient);

      if (!resolvedRecipient) {
        this.logger.warn(`Invalid email recipient: ${payload.recipient}`);
        return {
          success: false,
          channel: this.channel,
          error: `Invalid email recipient: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      const context = this.buildTemplateContext(payload);
      const html = this.renderTemplate(payload.type, context);
      const subject = this.renderSubject(payload.type, context);

      const message: EmailMessage = {
        to: resolvedRecipient,
        from: this.config.fromAddress,
        subject,
        body: payload.body,
        html,
        sentAt: new Date(),
        notificationId: payload.id,
      };

      if (this.config.transport) {
        await this.config.transport(message);
      }

      this.sentEmails.push(message);

      this.logger.info(`Email sent to ${resolvedRecipient}: ${subject}`);

      return {
        success: true,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        channel: this.channel,
        error: `Email delivery failed: ${errorMessage}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Validate and normalize an email recipient address.
   * Returns the normalized address, or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const trimmed = recipient.trim().toLowerCase();
    if (!EMAIL_REGEX.test(trimmed)) {
      return null;
    }
    return trimmed;
  }

  /**
   * Build a template context from a notification payload.
   */
  private buildTemplateContext(payload: NotificationPayload): TemplateContext {
    return {
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata ?? {},
      appName: this.config.appName,
      year: new Date().getFullYear(),
    };
  }

  /**
   * Render the email subject line, potentially with type-specific prefixes.
   */
  private renderSubject(type: NotificationType, context: TemplateContext): string {
    const prefixes: Record<NotificationType, string> = {
      order_confirmation: '',
      order_status_update: '',
      welcome: '',
      account_updated: '',
    };

    const prefix = prefixes[type];
    return prefix ? `${prefix} ${context.subject}` : context.subject;
  }

  /**
   * Render an HTML email template based on notification type.
   */
  renderTemplate(type: NotificationType, context: TemplateContext): string {
    const bodyContent = this.renderBodyForType(type, context);

    return [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">',
      `  <div style="background-color: #f8f9fa; padding: 20px; border-radius: 8px;">`,
      `    <h2 style="color: #333; margin-top: 0;">${this.escapeHtml(context.subject)}</h2>`,
      `    ${bodyContent}`,
      `  </div>`,
      `  <footer style="margin-top: 20px; padding-top: 10px; border-top: 1px solid #eee; color: #999; font-size: 12px;">`,
      `    <p>&copy; ${context.year} ${this.escapeHtml(context.appName)}. All rights reserved.</p>`,
      `  </footer>`,
      '</body>',
      '</html>',
    ].join('\n');
  }

  /**
   * Render type-specific body content.
   */
  private renderBodyForType(type: NotificationType, context: TemplateContext): string {
    switch (type) {
      case 'order_confirmation':
        return this.renderOrderConfirmation(context);
      case 'order_status_update':
        return this.renderOrderStatusUpdate(context);
      case 'welcome':
        return this.renderWelcome(context);
      case 'account_updated':
        return this.renderAccountUpdated(context);
      default:
        return `<p>${this.escapeHtml(context.body)}</p>`;
    }
  }

  private renderOrderConfirmation(context: TemplateContext): string {
    return [
      '<div style="background-color: #fff; padding: 15px; border-radius: 4px; margin: 10px 0;">',
      `  <p style="color: #28a745; font-weight: bold;">Order Received</p>`,
      `  <p>${this.escapeHtml(context.body)}</p>`,
      `  <p style="color: #666; font-size: 14px;">You will receive updates as your order is processed.</p>`,
      '</div>',
    ].join('\n');
  }

  private renderOrderStatusUpdate(context: TemplateContext): string {
    return [
      '<div style="background-color: #fff; padding: 15px; border-radius: 4px; margin: 10px 0;">',
      `  <p style="color: #007bff; font-weight: bold;">Order Status Update</p>`,
      `  <p>${this.escapeHtml(context.body)}</p>`,
      '</div>',
    ].join('\n');
  }

  private renderWelcome(context: TemplateContext): string {
    return [
      '<div style="background-color: #fff; padding: 15px; border-radius: 4px; margin: 10px 0;">',
      `  <p style="color: #6f42c1; font-weight: bold;">Welcome!</p>`,
      `  <p>${this.escapeHtml(context.body)}</p>`,
      `  <p style="color: #666; font-size: 14px;">Get started by exploring your dashboard.</p>`,
      '</div>',
    ].join('\n');
  }

  private renderAccountUpdated(context: TemplateContext): string {
    return [
      '<div style="background-color: #fff; padding: 15px; border-radius: 4px; margin: 10px 0;">',
      `  <p style="color: #fd7e14; font-weight: bold;">Account Updated</p>`,
      `  <p>${this.escapeHtml(context.body)}</p>`,
      `  <p style="color: #666; font-size: 14px;">If you did not make this change, please contact support immediately.</p>`,
      '</div>',
    ].join('\n');
  }

  /**
   * Escape HTML special characters to prevent XSS in email templates.
   */
  private escapeHtml(text: string): string {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept valid email addresses', () => {
      expect(adapter.resolveRecipient('alice@example.com')).toBe('alice@example.com');
      expect(adapter.resolveRecipient('bob.smith@company.co.uk')).toBe('bob.smith@company.co.uk');
    });

    it('should trim and lowercase emails', () => {
      expect(adapter.resolveRecipient('  Alice@Example.COM  ')).toBe('alice@example.com');
    });

    it('should reject invalid email addresses', () => {
      expect(adapter.resolveRecipient('')).toBeNull();
      expect(adapter.resolveRecipient('not-an-email')).toBeNull();
      expect(adapter.resolveRecipient('@no-local.com')).toBeNull();
      expect(adapter.resolveRecipient('no-domain@')).toBeNull();
      expect(adapter.resolveRecipient('spaces in@email.com')).toBeNull();
    });
  });

  describe('send', () => {
    it('should send email successfully for valid recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store sent email with correct fields', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('noreply@taskflowpro.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.body).toContain('Widget x2');
      expect(emails[0]?.html).toContain('<!DOCTYPE html>');
      expect(emails[0]?.notificationId).toBe('notif-0001');
      expect(emails[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should return failure for invalid recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email recipient');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return failure when transport throws', async () => {
      const failingAdapter = new EmailAdapter({
        transport: async () => { throw new Error('SMTP connection refused'); },
      });

      const result = await failingAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMTP connection refused');
    });

    it('should call custom transport when provided', async () => {
      const transport = vi.fn().mockResolvedValue(true);
      const customAdapter = new EmailAdapter({ transport });

      await customAdapter.send(makePayload());

      expect(transport).toHaveBeenCalledOnce();
      const message = transport.mock.calls[0]![0];
      expect(message.to).toBe('alice@example.com');
      expect(message.subject).toBe('Order Confirmation: order-1');
    });

    it('should normalize recipient email', async () => {
      await adapter.send(makePayload({ recipient: '  Alice@EXAMPLE.COM  ' }));

      const emails = adapter.getSentEmails();
      expect(emails[0]?.to).toBe('alice@example.com');
    });
  });

  describe('template rendering', () => {
    it('should render order confirmation template', async () => {
      await adapter.send(makePayload({ type: 'order_confirmation' }));

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('Order Received');
      expect(html).toContain('Widget x2');
      expect(html).toContain('updates as your order is processed');
    });

    it('should render order status update template', async () => {
      await adapter.send(makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      }));

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('Order Status Update');
      expect(html).toContain('pending');
      expect(html).toContain('confirmed');
    });

    it('should render welcome template', async () => {
      await adapter.send(makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, welcome to TaskFlow Pro. Your account has been created.',
      }));

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('Welcome!');
      expect(html).toContain('exploring your dashboard');
    });

    it('should render account updated template', async () => {
      await adapter.send(makePayload({
        type: 'account_updated',
        subject: 'Account Updated',
        body: 'Your account has been updated. Changed fields: name, email.',
      }));

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('Account Updated');
      expect(html).toContain('contact support');
    });

    it('should include footer with app name and year', async () => {
      await adapter.send(makePayload());

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('TaskFlow Pro');
      expect(html).toContain(`${new Date().getFullYear()}`);
      expect(html).toContain('All rights reserved');
    });

    it('should escape HTML in user-provided content', async () => {
      await adapter.send(makePayload({
        body: '<script>alert("xss")</script>',
        subject: 'Test <b>bold</b>',
      }));

      const html = adapter.getSentEmails()[0]?.html ?? '';
      expect(html).not.toContain('<script>');
      expect(html).toContain('&lt;script&gt;');
      expect(html).not.toContain('<b>bold</b>');
    });
  });

  describe('configuration', () => {
    it('should use custom from address', async () => {
      const customAdapter = new EmailAdapter({ fromAddress: 'support@myapp.com' });
      await customAdapter.send(makePayload());

      expect(customAdapter.getSentEmails()[0]?.from).toBe('support@myapp.com');
    });

    it('should use custom app name in templates', async () => {
      const customAdapter = new EmailAdapter({ appName: 'My Custom App' });
      await customAdapter.send(makePayload());

      const html = customAdapter.getSentEmails()[0]?.html ?? '';
      expect(html).toContain('My Custom App');
    });
  });

  describe('getSentEmails and clearSentEmails', () => {
    it('should return copies of sent emails', async () => {
      await adapter.send(makePayload());

      const emails1 = adapter.getSentEmails();
      const emails2 = adapter.getSentEmails();
      expect(emails1).not.toBe(emails2);
      expect(emails1).toEqual(emails2);
    });

    it('should clear sent email history', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

